window.__QUIZ_DATA__=[{"id":"theory>Geography>2006>SECTION A>1>a","subject":"Geography","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"What is transportation ?","images":[],"marking_scheme":"Transportation is the movement of people,goods and services from one place to the other.In other words transportation is the movement of people,goods and commodities from one place to another either by land,water or air.","marks":"8","difficulty":"1"},{"id":"theory>Geography>2006>SECTION A>1>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Highlight four advantages of air transportation","images":[],"marking_scheme":"-It is the fastest means of transportation  -It uses direct routes  -It can reach any place provided there are landing facilities  -There are no obstruction as it can cross mountains,dense forests and large oceans with great ease and speed.  -Urgently required medicare supplies,machine parts,express mails are easily dispatched by aeroplanes  -It can carry valuable and perishable cargoes  -It is very comfortable  -No cost is incurred in establishing air routes  -It is best suited for passanger traffic  -There are no obstructions like mountains,seas, oceans, lakes and forest.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2006>SECTION A>1>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Describe Five contribution of transportationto economic development","images":[],"marking_scheme":"-Transportation ensures the movement of people   -Transportation ensures the movement of goods and services  -All means of transportation provide employment opportunity  -Transportation promote national and international trade  -Transportation enhance national integration  -Diffusion of ideas,Innovations and technology through transportation  -Through various means of transportation, new areas are opened for development.  -All means of transportation generate revenue to the government.  -Transportation helps to foster goods international relationship between various countries  -Through transportation, different natural resources are discovered and exploited in a country.  -Transportation promote tourism  -Transportation enables people to increase their production either in agricultural,mineral or industrial.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2006>SECTION A>2>a","subject":"Geography","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Give five reasons why your county has more trading partners outside Africa","images":[],"marking_scheme":"-There is low level of technology in African countries  -Because there is need to have stronger currencies  -There is difference in prices of goods  -There are differences in import duties  -There is high level of savings in developed countries  -There is political instability  -Colonial ties  -There is trade restrictions among African countries(ban on importation)  -Poor transportation links with other African states  -Preference of goods produced outside Africa.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2006>SECTION A>2>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"Outline any five ways by which the trade between your country and other countries could be improved.","images":[],"marking_scheme":"-Specialisation of production  -Improvement in technology  -Construction of trans-continental transport networks  -Formation of African Economic Union  -Restriction in tariffs  -Removal of all barriers  -Protection of local goods from foreign competition  -Use of common currency  -Promotion of common language  -Stable government  -Promotion of local goods  -Encouraging saving capacity of the people  -Adding values to our export product.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2006>SECTION A>3>a","subject":"Geography","year":"2006","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline any four advantages of concerntration of industries in the urban areas","images":[],"marking_scheme":"-It encourages the development of infrastructure  -It encourages the development of organised markets  -Promotion of research centres  -Presence of capital  -Linkage of industries   -Presence of skilled and unskilled labour  -Development of skilled man power  -Improvement in the standard of living  -Creation of employment opportunities","marks":"10","difficulty":"2"},{"id":"theory>Geography>2006>SECTION A>3>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Highlight any three disadvantages of  concentration of industries in urban areas","images":[],"marking_scheme":"-Environmental pollution/health hazards/poor waste management.  -Encourage rural-urban migration  -Destruction of the ecosystem  -Pressure on land  -Pressure on social amenities/infrastructure  -Uneven development  -Loss of farmlands  -Leads to congestion e.g traffic, industries, housing etc  -Structural employment due to low demand for industrial goods  -Increase in crime rate   -Target of attacking during war time  -Development of slums/ghettos","marks":"5","difficulty":"2"},{"id":"theory>Geography>2006>SECTION A>3>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Describe three factors responsible for the dominance of light industries in the developing countries","images":[],"marking_scheme":"-Less capital intensive  -Availability of labour(Unskilled labour)  -Availability of local raw materials  -Low energy consumption  -Inadequate capital  -Inadequate skilled labour  -Inadequate managerial skills  -Production of consumer goods  -Inadequate infrastructure.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>4>a>i","subject":"Geography","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw an outline map of Nigeria, on the map show  and name    one area important for cattle rearing","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Geography>2006>SECTION B>4>a>ii","subject":"Geography","year":"2006","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw an outline map of Nigeria, on the map show  and name  one area in the palm oil production","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Geography>2006>SECTION B>4>a>iii","subject":"Geography","year":"2006","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : RESOURCES","question":"Draw an outline map of Nigeria, on the map show  and name  one town in the oil palm production area","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>4>a>iv","subject":"Geography","year":"2006","type":"Theory","sub_label":"iv","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw an outline map of Nigeria, on the map show  and name  two town in the cattle rearing area","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>4>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Outline any three factor that favour cattle rearing in the area shown in 4(a)(ii)above","images":[],"marking_scheme":"-Abundant pasture/Savanna vegetation  -Availability of grazing land/wide plains  -Absence of tse-tse flies in cattle rearing area   -Favourable climate e.g rainfall of 50-125cm  -Per annum for grass growth  -Availability of water  -Presence of animal rearing experts  -Cattle as symbol of wealth  -Availability of market   -Low relative humidity  -Wide range of temperature  -Presence of tse-tse resistant type of cattle e.gZebu/ndama type","marks":"4","difficulty":"1"},{"id":"theory>Geography>2006>SECTION B>4>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Highlight any three ways in which cattle rearing is of improtance to Nigeria","images":[],"marking_scheme":"-It provide employment   -It is a source of income to farmers  -It is a source of raw materials for industries  -It is a source of foreign exchange   -It is a source of food  -Cattle animals are used for ploughing  -It is a source of organic manure  -The animal dungs serves as fueL  -Revenue to government as cattle tax (Jangali)  -The animals are used as means of transportation","marks":"5","difficulty":"1"},{"id":"theory>Geography>2006>SECTION B>5>a>i","subject":"Geography","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Draw an outlne map of Nigeria. on the map, show and name    lake Kaini","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"5","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>5>a>ii","subject":"Geography","year":"2006","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw an outlne map of Nigeria. on the map, show and name  one area with extinct volcano","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>5>a>iii","subject":"Geography","year":"2006","type":"Theory","sub_label":"iii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw an outlne map of Nigeria. on the map, show and name  The udi hills","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>5>a>iv","subject":"Geography","year":"2006","type":"Theory","sub_label":"iv","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Draw an outlne map of Nigeria. on the map, show and name  The river Hadeijia","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>5>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"Highlight any four problems of development in th eastern borderland","images":[],"marking_scheme":"-Rugged relief  -Remoteness in accessibility  -Poor transportation network  -Soil erosion  -Scanty rainfall/drought  -Poor quality pasture   -Inadequate surface drinking water  -Low water table  -Absence of mineral resources  -Excessive flooding of the lowlands  -Land fragmentation  -Land Infertility due to continuous cropping  -Rural urban migration/drift  -Environmental degradation eg coal mining/over grazing.","marks":"3","difficulty":"3"},{"id":"theory>Geography>2006>SECTION B>5>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ISSUES ON DEVELOPMENT AND ENVIRONMENTAL CONCERNS","question":"outline two solutions to any problems highlighted in 5(b) above","images":[],"marking_scheme":"-Construction of better roads  -Provision of irrigation schemes  -Provision of clean and reliable water supply  -Use of fertlizers and manure to improve soil fertility  -Development of cattle ranch  -Strip farming/terrace farming  -Channelization of water courses  -Review of land use decree  -Co-operative farming provision of amenities in rural areas","marks":"3","difficulty":"1"},{"id":"theory>Geography>2006>SECTION B>6>a>i","subject":"Geography","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : NIGERIA ON BROAD OUTLINE","question":"Draw an outline map of Nigeria, on the map show and name;    one area important for cattle rearing","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"5","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>6>a>ii","subject":"Geography","year":"2006","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Draw an outline map of Nigeria, on the map show and name;  one are of moderate population","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>6>a>iii","subject":"Geography","year":"2006","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Draw an outline map of Nigeria, on the map show and name;  one area of dense population","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION B>6>a>iv","subject":"Geography","year":"2006","type":"Theory","sub_label":"iv","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"one town in 6(ai) above","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"1"},{"id":"theory>Geography>2006>SECTION B>6>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Outline three factors resposible for the dense population i the area shown in 6(a)(iii) above","images":[],"marking_scheme":"-Favourable climate  -Fertile soil  -Historical factor  -Industrialisation  -Availability of natural resources eg mineral  -Cultural attachment to land  -Favourable relief  -Administrative centres  -Employment opportunities  -Presence of social amenities  -Commercial activities  -Rural-urban migration  -Educational centre  -Development of ports","marks":"3","difficulty":"3"},{"id":"theory>Geography>2006>SECTION B>6>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Highlight three problems of dense ppulation in 6(a)(iii) above","images":[],"marking_scheme":"-Insufficient food  -High cost of living  -Shortage of land for development  -High cost of land","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION C>7>a>i","subject":"Geography","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa on the map, show and name the    River nile","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"5","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>7>a>ii","subject":"Geography","year":"2006","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa on the map, show and name the   River niger","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>7>a>iii","subject":"Geography","year":"2006","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa on the map, show and name the   River orange","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>7>a>iv","subject":"Geography","year":"2006","type":"Theory","sub_label":"iv","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of Africa on the map, show and name the   River zambezi","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>7>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Describe four charateristics of African rivers","images":[],"marking_scheme":"-Most of the river are shallow  -Most of the river are characterized by rapids,cataracts and water falls  -There is seasonal flunctuation in the volume of water  -Many African rivers contain debris or sediments such as leaves,mud etc  -Most African rivers are short and fast flowing  -Most African rivers are seasonal in nature  -They flow only during the rainy seasons  -Most African rivers changes their colours especially during rainy season mainly because of the sediments they carry during this time.  -Some rivers have weeds/floating vegetation.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION C>7>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Highlght three uses of African rivers","images":[],"marking_scheme":"-It is used to develop ports to aid transportation  -For domestic purposes  -For industrial purposes  -Irrigation  -For fishing which create employment  -Alluvial soils for agriculture  -Generation of Hydro-electric power(HEP)  -For tourism  -Presence of minerals e.g alluvial gold,diamond.  -Used as natural/political boundaries  -Source of proteinous food","marks":"3","difficulty":"2"},{"id":"theory>Geography>2006>SECTION C>8>a>i","subject":"Geography","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Draw a sketch map of Africa on the map show and name    one area that recieves rainfall in winter","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>8>a>ii","subject":"Geography","year":"2006","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Draw a sketch map of Africa on the map show and name   The dominant air mass over Africa in july","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>8>a>iii","subject":"Geography","year":"2006","type":"Theory","sub_label":"iii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Draw a sketch map of Africa on the map show and name   the position of ITCZ in july","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Geography>2006>SECTION C>8>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Explain the effectof a altitude on the climate of Africa","images":[],"marking_scheme":"-Temperature decrease with altitude at an average rate of 6.5 \u2218C for approximately 1000m of vertical ascent.  -High altitude areas have less dust and water vapour and so allows the heat to escape rapidly  -Since the atmosphere is heated by conduction, areas close to the earth's surface are this warmer.  -In high altitudes areas like Jos, there is little air to distribute the heat hence cooler climate is experienced.  -Nairobi and Mombasa for instance are almost on the same latitude but Nairobi on a higher latitude (1675m) has lower means annual temperatures than Mombasa (16m)  -High altitude area experience high amount of rainfall because of the Orographic effect on the windward side, rainfall is higher than surrounding areas.  -On the leeward side, the rainfall is either scanty or low.","marks":"5","difficulty":"2"},{"id":"theory>Geography>2006>SECTION C>9>a>i","subject":"Geography","year":"2006","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of West Africa . on the map locate and name    one English speaking country","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"10","difficulty":"1"},{"id":"theory>Geography>2006>SECTION C>9>a>ii","subject":"Geography","year":"2006","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of West Africa . on the map locate and name  one french speaking country","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"1"},{"id":"theory>Geography>2006>SECTION C>9>a>iii","subject":"Geography","year":"2006","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of West Africa . on the map locate and name  one portuguese speacking country","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"1"},{"id":"theory>Geography>2006>SECTION C>9>a>iv","subject":"Geography","year":"2006","type":"Theory","sub_label":"iv","group":"","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Draw a sketch map of West Africa . on the map locate and name  The capital cities of any two in (a)(i)-(iii)","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"2","difficulty":"2"},{"id":"theory>Geography>2006>SECTION C>9>b","subject":"Geography","year":"2006","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Highlight three achievement of Ecowas since inception","images":[],"marking_scheme":"-Development of common market  -Free movement of people   -Trade liberation  -Cultural integration  -Educational interaction  -Scientific/technical cooperation  -Promotion of unity  -Monetary union  -Right to settle anywhere  -Conflict resolution  -Development of international communication.  -Links within the sub-region  -Promotion of sports e.g WAFU cups","marks":"2","difficulty":"2"},{"id":"theory>Geography>2006>SECTION C>9>c","subject":"Geography","year":"2006","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"Outine two problems working againstthe achievement of the obectives of Ecowas","images":[],"marking_scheme":"-Similarity of products fear of domination  -Different political Ideologies  -Poverty and hence inability to pay up dues  -Language differences  -Colonial ties  -Political instability  -Poor transport network  -Poor communication system  -Non-implementation of agreed programmes and resolutions  -Problem of debt burden affecting many members  -Artificial barriers to trade  -Existence of other sub-regional organization.","marks":"2","difficulty":"2"}];